      if (diffMinutesEarly <= 10) {
        calcEnd = sEnd;
      } else {
        calcEnd = aOut;
      }
    }
    diffMs = calcEnd - calcStart;
  }
  if (diffMs < 0) return '0h 00p';
  const totalMinutes = Math.floor(diffMs / (1000 * 60));
